const body = $input.first().json.body || $input.first().json;
const event = body;
const invoice = event?.data?.object || {};

const customerId = invoice.customer || '';
const invoiceId = invoice.id || '';
const invoicePdfUrl = invoice.invoice_pdf || '';
const hostedInvoiceUrl = invoice.hosted_invoice_url || '';
const amountDue = invoice.amount_due || 0;
const currency = (invoice.currency || 'usd').toUpperCase();
const amountDisplay = `$${(amountDue / 100).toFixed(2)} ${currency}`;
const status = invoice.status || '';

// Billing period
const periodStart = invoice.period_start
  ? new Date(invoice.period_start * 1000).toLocaleDateString('en-US', { month: 'long', day: 'numeric', year: 'numeric' })
  : '';
const periodEnd = invoice.period_end
  ? new Date(invoice.period_end * 1000).toLocaleDateString('en-US', { month: 'long', day: 'numeric', year: 'numeric' })
  : '';
const billingPeriod = periodStart && periodEnd ? `${periodStart} – ${periodEnd}` : 'Current billing period';
const periodStartIso = invoice.period_start ? new Date(invoice.period_start * 1000).toISOString() : null;
const periodEndIso = invoice.period_end ? new Date(invoice.period_end * 1000).toISOString() : null;
const invoiceNumber = invoice.number || invoiceId;
const dueDate = invoice.due_date
  ? new Date(invoice.due_date * 1000).toLocaleDateString('en-US', { month: 'long', day: 'numeric', year: 'numeric' })
  : 'Upon receipt';

return [{ json: {
  customerId,
  invoiceId,
  invoiceNumber,
  invoicePdfUrl,
  hostedInvoiceUrl,
  amountDue,
  amountDisplay,
  currency,
  status,
  billingPeriod,
  periodStartIso,
  periodEndIso,
  dueDate,
  createdAt: new Date().toISOString(),
  rawPayload: JSON.stringify(body)
} }];

const users = $input.first().json;
const user = Array.isArray(users) ? users[0] : users;
const parsed = $('Parse Invoice Payload').first().json;

const planDisplayNames = { free: 'Free', starter: 'Starter', pro: 'Pro', scale: 'Scale' };
const planTier = user?.plan_tier || 'starter';
const planDisplay = planDisplayNames[planTier] || planTier;

return [{ json: {
  ...parsed,
  userId: user?.id || '',
  email: user?.email || '',
  firstName: user?.first_name || 'there',
  planTier,
  planDisplay
} }];

